class SAMLValidator {
    private String expectedAudience;
    private String expectedRecipient;
    
    public SAMLValidator(String expectedAudience, String expectedRecipient) {
        this.expectedAudience = expectedAudience;
        this.expectedRecipient = expectedRecipient;
    }
    
    public void validate(SAMLResponse response) throws SAMLException {
        if (response.getId() == null || response.getId().isEmpty()) {
            throw new SAMLException("SAML Response ID is missing");
        }
        
        if (response.getIssuer() == null || response.getIssuer().isEmpty()) {
            throw new SAMLException("SAML Response Issuer is missing");
        }
        
        if (!"urn:oasis:names:tc:SAML:2.0:status:Success".equals(response.getStatus())) {
            throw new SAMLException("SAML Response status is not Success");
        }
        
        for (Assertion assertion : response.getAssertions()) {
            validateAssertion(assertion);
        }
    }
    
    private void validateAssertion(Assertion assertion) throws SAMLException {
        if (assertion.getId() == null || assertion.getId().isEmpty()) {
            throw new SAMLException("Assertion ID is missing");
        }
        
        if (assertion.getIssuer() == null || assertion.getIssuer().isEmpty()) {
            throw new SAMLException("Assertion Issuer is missing");
        }
        
        if (assertion.getSubject() == null) {
            throw new SAMLException("Assertion Subject is missing");
        }
        
        validateSubject(assertion.getSubject());
        
        if (assertion.getConditions() != null) {
            validateConditions(assertion.getConditions());
        }
    }
    
    private void validateSubject(Subject subject) throws SAMLException {
        if (subject.getNameID() == null || subject.getNameID().isEmpty()) {
            throw new SAMLException("Subject NameID is missing");
        }
        
        if (subject.getSubjectConfirmation() != null) {
            SubjectConfirmation subjectConf = subject.getSubjectConfirmation();
            
            if (!"urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(subjectConf.getMethod())) {
                throw new SAMLException("Invalid SubjectConfirmation method");
            }
            
            if (subjectConf.getData() != null) {
                SubjectConfirmationData data = subjectConf.getData();
                
                if (expectedRecipient != null && !expectedRecipient.equals(data.getRecipient())) {
                    throw new SAMLException("SubjectConfirmationData Recipient does not match expected value");
                }
                
                if (data.getNotOnOrAfter() != null && Instant.now().isAfter(data.getNotOnOrAfter())) {
                    throw new SAMLException("SubjectConfirmationData has expired");
                }
            }
        }
    }
    
    private void validateConditions(Conditions conditions) throws SAMLException {
        Instant now = Instant.now();
        
        if (conditions.getNotBefore() != null && now.isBefore(conditions.getNotBefore())) {
            throw new SAMLException("Assertion is not yet valid");
        }
        
        if (conditions.getNotOnOrAfter() != null && now.isAfter(conditions.getNotOnOrAfter())) {
            throw new SAMLException("Assertion has expired");
        }
        
        if (expectedAudience != null && !conditions.getAudienceRestrictions().isEmpty()) {
            if (!conditions.getAudienceRestrictions().contains(expectedAudience)) {
                throw new SAMLException("AudienceRestriction does not include expected audience");
            }
        }
    }
}

